from __future__ import annotations
import time
from typing import Any

from .bus import KWinBus, ScriptRunner
from .models import DesktopInfo, ScreenInfo


class DesktopManager:
    """
    Enumerates and looks up virtual desktops and screens.

    Virtual desktops are read from the VirtualDesktopManager D-Bus interface
    which is always reliable.  Screens are read via a KWin script since
    workspace.screens is only available inside the scripting sandbox.
    """

    def __init__(self, kwin: KWinBus, runner: ScriptRunner) -> None:
        self._kwin   = kwin
        self._runner = runner

    # ── Virtual Desktops ──────────────────────────────────────────────────────

    def list_desktops(self) -> list[DesktopInfo]:
        """
        Return all virtual desktops ordered by x11 number (1-based).
        Uses VirtualDesktopManager D-Bus property — fast, no script needed.
        """
        try:
            raw = list(self._kwin.vdm.desktops)
            return [
                DesktopInfo(
                    id     = str(item[1]),
                    name   = str(item[2]),
                    number = int(item[0]),
                )
                for item in raw
            ]
        except Exception as exc:
            raise RuntimeError(f"Cannot read virtual desktops: {exc}") from exc

    def current_desktop_id(self) -> str:
        """Return the UUID of the currently active virtual desktop."""
        try:
            return str(self._kwin.vdm.current)
        except Exception as exc:
            raise RuntimeError(f"Cannot read current desktop: {exc}") from exc

    def find_desktop(
        self,
        *,
        name:   str | None = None,
        number: int | None = None,
        id:     str | None = None,
    ) -> DesktopInfo | None:
        """
        Find a desktop by name, 1-based number, or UUID.
        Returns None if not found.  Raises ValueError if no criteria given.
        """
        if name is None and number is None and id is None:
            raise ValueError("Provide at least one of: name, number, id")
        for d in self.list_desktops():
            if id     is not None and d.id     == id:     return d
            if number is not None and d.number == number: return d
            if name   is not None and d.name   == name:   return d
        return None

    # ── Screens ───────────────────────────────────────────────────────────────

    def list_screens(self) -> list[ScreenInfo]:
        """
        Return all connected screens via workspace.screens in a KWin script.
        """
        result = self._runner.run("list_screens", """
var screens = workspace.screens;
var arr = [];
for (var i = 0; i < screens.length; i++) {
    var s = screens[i];
    arr.push({
        name:         String(s.name         || ""),
        manufacturer: String(s.manufacturer || ""),
        model:        String(s.model        || ""),
        x:      Number(s.geometry ? s.geometry.x      : 0),
        y:      Number(s.geometry ? s.geometry.y      : 0),
        width:  Number(s.geometry ? s.geometry.width  : 0),
        height: Number(s.geometry ? s.geometry.height : 0),
    });
}
send({ screens: arr });
""")
        if "fatalError" in result:
            raise RuntimeError(f"list_screens script error: {result['fatalError']}")
        if "timeout" in result:
            raise RuntimeError("list_screens timed out")

        return [
            ScreenInfo(
                name         = s.get("name", ""),
                x            = int(s.get("x", 0)),
                y            = int(s.get("y", 0)),
                width        = int(s.get("width", 0)),
                height       = int(s.get("height", 0)),
                manufacturer = s.get("manufacturer", ""),
                model        = s.get("model", ""),
            )
            for s in result.get("screens", [])
        ]

    def find_screen(
        self,
        *,
        name:  str | None = None,
        index: int | None = None,
    ) -> ScreenInfo | None:
        """
        Find a screen by connector name (e.g. "HDMI-A-2") or index.
        Returns None if not found.
        """
        if name is None and index is None:
            raise ValueError("Provide at least one of: name, index")
        screens = self.list_screens()
        if index is not None:
            if 0 <= index < len(screens):
                return screens[index]
            return None
        for s in screens:
            if s.name == name:
                return s
        return None

    def switch_to_desktop(
        self,
        desktop:  DesktopInfo,
        settle_s: float = 0.4,
    ) -> None:
        """
        Make the given virtual desktop the active (visible) desktop.

        Uses a KWin script to assign workspace.currentDesktop.  Blocks for
        settle_s seconds after the switch so that KWin has time to commit
        the change before the caller issues tile or move operations.

        Args:
            desktop:  The target DesktopInfo (from list_desktops).
            settle_s: Seconds to wait after the switch (default 0.4).
                      Pass a smaller value (e.g. 0.2) for the restore-to-
                      original step where minimal delay is needed.

        Raises:
            RuntimeError if the desktop is not found by the script.
        """
        target_id = desktop.id
        result = self._runner.run("switch_to_desktop", f"""
var targetId = "{target_id}";
var desks    = workspace.desktops;
var found    = false;
for (var i = 0; i < desks.length; i++) {{
    if (String(desks[i].id || "") === targetId) {{
        workspace.currentDesktop = desks[i];
        found = true;
        break;
    }}
}}
send({{ ok: found, op: "switch_to_desktop", id: targetId }});
""")
        if not result.get("ok"):
            raise RuntimeError(
                f"switch_to_desktop: desktop {desktop.name!r} "
                f"({target_id!r}) not found in workspace.desktops"
            )
        time.sleep(settle_s)

    def active_window_and_cursor(self) -> dict:
        """
        Return the active window's internalId, caption, and the current cursor
        position in a single KWin script round-trip.

        Used by kwin_mouse-clicks.py to identify which window was clicked
        and where, without two separate script calls.

        Returns a dict with keys:
            active_id  -- internalId with braces stripped, or "" if none
            caption    -- window title (caption property), or "" if none
            cursor_x   -- X coordinate of the pointer (compositor space)
            cursor_y   -- Y coordinate of the pointer (compositor space)
        """
        result = self._runner.run("active_window_and_cursor", """
var w  = workspace.activeWindow;
var cp = workspace.cursorPos;
send({
    ok:        true,
    op:        "active_window_and_cursor",
    active_id: w  ? String(w.internalId).replace(/[{}]/g, "") : "",
    caption:   w  ? String(w.caption || "") : "",
    cursor_x:  cp ? Number(cp.x) : 0,
    cursor_y:  cp ? Number(cp.y) : 0,
});
""")
        return {
            "active_id": str(result.get("active_id", "")),
            "caption":   str(result.get("caption",   "")),
            "cursor_x":  int(result.get("cursor_x",  0)),
            "cursor_y":  int(result.get("cursor_y",  0)),
        }

    def screen_for_point(self, x: int, y: int) -> ScreenInfo | None:
        """Return the screen that contains the given compositor coordinates."""
        for s in self.list_screens():
            if s.contains_point(x, y):
                return s
        return None
